# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

from flask import Flask, request, jsonify
from web3 import Web3

app = Flask(__name__)

@app.route('/verify_signature', methods=['POST'])
def verify_signature():
    data = request.get_json()
    message = data['message']
    signature = data['signature']
    public_address = data['publicAddress']

    # Create a Web3 instance
    w3 = Web3()

    # Recover the address from the signature
    recovered_address = w3.eth.account.recoverMessage(
        message.encode('utf-8'),
        signature=signature
    )

    # Compare the recovered address with the provided public address
    if recovered_address.lower() == public_address.lower():
        return jsonify({'status': 'success', 'message': 'Signature verified'})
    else:
        return jsonify({'status': 'error', 'message': 'Invalid signature'})

if __name__ == '__main__':
    app.run(debug=True)